function resolveQuickSiteAlias(raw) {
    if (!raw || typeof raw !== 'string') return '';
    const q = raw.trim().toLowerCase();
    if (!q || q.includes(' ') || q.includes('.') || q.includes('/')) return '';
    if (!/^[a-z0-9-]+$/.test(q)) return '';
    return QUICK_SITE_ALIASES[q] || '';
}

function normalizeUrl(raw) {
    if (!raw || typeof raw !== 'string') return '';
    raw = raw.trim(); if (!raw) return '';

    // Known one-word website shortcuts: tiktok, youtube, github, ...
    if (DB.getSettings().quickWebSearch !== false) {
        const quickSite = resolveQuickSiteAlias(raw);
        if (quickSite) return quickSite;
    }

    if (/^0x[0-9a-fA-F]{40}$/.test(raw)) return 'https://etherscan.io/address/' + raw;
    if (/\.eth$/i.test(raw)) return 'https://app.ens.domains/name/' + raw;
    if (/^[a-z][a-z0-9+\-.]*:\/\//i.test(raw)) return raw;
    // IPv4 address or localhost (with optional port/path) → http://
    if (/^(?:localhost|(?:\d{1,3}\.){3}\d{1,3})(:\d+)?(\/.*)?$/.test(raw)) return 'http://' + raw;
    if (/^[a-zA-Z0-9-]+(\.[a-zA-Z]{2,})+/.test(raw) && !raw.includes(' ')) return 'https://' + raw;
    // Use configured search engine
    const se = DB.getSettings().searchEngine || 'Google';
    const q = encodeURIComponent(raw);
    const engines = { 'Google': 'https://www.google.com/search?q=', 'DuckDuckGo': 'https://duckduckgo.com/?q=', 'Bing': 'https://www.bing.com/search?q=', 'Brave Search': 'https://search.brave.com/search?q=', 'Ecosia': 'https://www.ecosia.org/search?q=', 'Yahoo': 'https://search.yahoo.com/search?p=' };
    return (engines[se] || engines['Google']) + q;
}
