document.getElementById('aiInspectRun')?.addEventListener('click', async () => {
    const tab = getActiveTab();
    if (!tab?.url || !tab.url.startsWith('http')) { showToast('❌ Nema aktivne HTTP/S stranice za analizu'); return; }
    const verdictEl = document.getElementById('aiInspectVerdict');
    const scoreEl = document.getElementById('aiInspectScore');
    const barEl = document.getElementById('aiInspectScoreBar');
    const reasonsEl = document.getElementById('aiInspectReasons');
    const pageInfoEl = document.getElementById('aiInspectPageInfo');
    verdictEl.textContent = '⏳ Analiziranje...';
    scoreEl.textContent = '…';
    barEl.style.width = '0%';
    reasonsEl.innerHTML = '';
    pageInfoEl.textContent = '⏳ Učitavanje...';
    try {
        const result = await window.etherx?.ai?.checkPhishing?.(tab.url, tab.title || '');
        if (result) {
            const score = Math.round(result.score ?? result.riskScore ?? 0);
            scoreEl.textContent = score;
            const color = score < 40 ? '#4ade80' : score < 70 ? '#facc15' : '#f87171';
            const grad = score < 40 ? 'linear-gradient(90deg,#4ade80,#22c55e)' : score < 70 ? 'linear-gradient(90deg,#facc15,#eab308)' : 'linear-gradient(90deg,#f87171,#ef4444)';
            scoreEl.style.color = color;
            barEl.style.width = score + '%';
            barEl.style.background = grad;
            verdictEl.textContent = score < 40 ? '✅ Stranica izgleda sigurna' : score < 70 ? '⚠️ Sumnjiva aktivnost otkrivena' : '🚨 Visok rizik — mogući phishing!';
            reasonsEl.innerHTML = (result.reasons || result.flags || []).map(r => `<div style="font-size:11px;color:var(--text3);padding:2px 0">• ${escHtml(String(r))}</div>`).join('');
        } else {
            verdictEl.textContent = '⚠️ AI analiza nije dostupna';
        }
    } catch (e) {
        verdictEl.textContent = '❌ Greška: ' + escHtml(e.message);
    }
    try {
        const url = new URL(tab.url);
        pageInfoEl.innerHTML = `<b>URL:</b> ${escHtml(tab.url)}<br><b>Domena:</b> ${escHtml(url.hostname)}<br><b>Protokol:</b> ${escHtml(url.protocol)}<br><b>Naslov:</b> ${escHtml(tab.title || '–')}`;
    } catch (_) {
        pageInfoEl.textContent = tab.url;
    }
});

const aiTextInputEl = document.getElementById('aiInspectTextInput');
const aiTextOutputEl = document.getElementById('aiInspectTextOutput');
let aiTranslateTypingTimer = null;

async function translateTextFallback(text, targetLang) {
    const cleanText = String(text || '').trim();
    const cleanLang = String(targetLang || '').trim() || 'en';
    if (!cleanText) return '';

    try {
        const tr = await window.etherx?.ai?.translate?.(cleanText, cleanLang);
        const out = tr?.translated ?? tr?.translation ?? tr?.text ?? (typeof tr === 'string' ? tr : '');
        if (String(out || '').trim()) return String(out).trim();
    } catch (_) { }

    try {
        const url = 'https://translate.googleapis.com/translate_a/single?client=gtx&sl=auto&tl='
            + encodeURIComponent(cleanLang) + '&dt=t&q=' + encodeURIComponent(cleanText);
        const response = await fetch(url);
        if (!response.ok) throw new Error('HTTP ' + response.status);
        const data = await response.json();
        const translated = Array.isArray(data?.[0])
            ? data[0].map(part => part?.[0] || '').join('').trim()
            : '';
        return translated || cleanText;
    } catch (_) {
        return cleanText;
    }
}

function resolveAiTranslateConfig() {
    const panelModelSel = document.getElementById('aiTranslateModel')?.value || '__settings__';
    const settingsModelSel = document.getElementById('settingsTranslateModel')?.value || '__main__';
    const settingsProviderSel = document.getElementById('settingsTranslateProvider')?.value || '__main__';
    let translateModel;
    let translateProvider;
    if (panelModelSel !== '__settings__') {
        translateModel = panelModelSel;
    } else if (settingsModelSel !== '__main__') {
        translateModel = settingsModelSel;
    } else {
        translateModel = getSelectedAiModel();
    }
    if (settingsProviderSel !== '__main__') {
        translateProvider = settingsProviderSel;
    } else {
        translateProvider = getSelectedAiProvider();
    }
    const maxChars = parseInt(document.getElementById('settingsTranslateMaxChars')?.value || '2000', 10);
    return { translateModel, translateProvider, maxChars };
}

function setTranslateResult(el, value) {
    if (!el) return;
    if ('value' in el) {
        el.value = value;
        return;
    }
    el.textContent = value;
    el.style.display = 'block';
}

function clearTranslateResult(el) {
    if (!el) return;
    if ('value' in el) {
        el.value = '';
        return;
    }
    el.textContent = '';
    el.style.display = 'none';
}

async function runAiTranslate(text, lang, langName, resultEl, infoEl, btn) {
    const { translateModel, translateProvider, maxChars } = resolveAiTranslateConfig();
    const trimmed = String(text || '').slice(0, maxChars);
    if (!trimmed) {
        clearTranslateResult(resultEl);
        if (infoEl) infoEl.textContent = '';
        return;
    }
    if (infoEl) infoEl.textContent = `📝 ${trimmed.length} znakova · 🤖 ${translateProvider}/${translateModel}`;
    if (btn) {
        btn.disabled = true;
        btn.textContent = '⏳…';
    }
    try {
        const prompt = `Prevedi sljedeći tekst na jezik: "${langName}" (${lang}). Vrati SAMO prijevod, bez objašnjenja, naslova ili uvodne rečenice.\n\n${trimmed}`;
        const translated = await runAiTextRequest(prompt, {
            provider: translateProvider,
            model: translateModel,
            maxOutputTokens: 2000,
            systemPrompt: `Ti si profesionalni prevoditelj. Prevedi tekst precizno i prirodno na zadani jezik.`
        });
        if (!String(translated || '').trim()) {
            const fallback = await translateTextFallback(trimmed, lang);
            setTranslateResult(resultEl, fallback || '(prazan odgovor)');
        } else {
            setTranslateResult(resultEl, translated);
        }
    } catch (e) {
        setTranslateResult(resultEl, '❌ ' + (e.message || String(e)));
    } finally {
        if (btn) {
            btn.disabled = false;
            btn.textContent = '🌐 Prevedi';
        }
    }
}

document.getElementById('aiInspectTranslate')?.addEventListener('click', async () => {
    const tab = getActiveTab();
    if (!tab?.url) { showToast('❌ Nema aktivne stranice'); return; }
    const lang = document.getElementById('aiInspectLang')?.value || 'hr';
    const langName = document.getElementById('aiInspectLang')?.selectedOptions?.[0]?.text || lang;
    const resultEl = document.getElementById('aiInspectTranslateResult');
    const infoEl = document.getElementById('aiTranslateInfo');
    const btn = document.getElementById('aiInspectTranslate');

    const inputText = aiTextInputEl?.value || '';
    if (inputText.trim()) {
        await runAiTranslate(inputText, lang, langName, aiTextOutputEl, infoEl, btn);
        return;
    }

    clearTranslateResult(resultEl);
    try {
        const wv = document.querySelector(`webview[data-tab-id="${STATE.activeTabId}"]`);
        let text = tab.title || '';
        if (wv && window.safeExecuteJS) {
            text = await window.safeExecuteJS(wv, 'document.body?.innerText?.slice(0,8000)||""').catch(() => tab.title || '');
        }
        await runAiTranslate(text, lang, langName, resultEl, infoEl, btn);
    } catch (e) {
        setTranslateResult(resultEl, '❌ ' + (e.message || String(e)));
    }
});

aiTextInputEl?.addEventListener('input', () => {
    if (aiTranslateTypingTimer) clearTimeout(aiTranslateTypingTimer);
    const text = aiTextInputEl.value || '';
    if (!text.trim()) {
        clearTranslateResult(aiTextOutputEl);
        return;
    }
    aiTranslateTypingTimer = setTimeout(() => {
        const lang = document.getElementById('aiInspectLang')?.value || 'hr';
        const langName = document.getElementById('aiInspectLang')?.selectedOptions?.[0]?.text || lang;
        runAiTranslate(text, lang, langName, aiTextOutputEl, document.getElementById('aiTranslateInfo'));
    }, 450);
});

