// Auto-apply Chrome UA for Google login/account pages
function isGoogleLoginDomain(url) {
    try {
        const u = new URL(url);
        const host = u.hostname.toLowerCase();
        // Google login/account domains that require Chrome UA
        return host === 'accounts.google.com'
            || host === 'myaccount.google.com'
            || host.endsWith('.accounts.google.com')
            || (host.endsWith('google.com') && (u.pathname.includes('/signin') || u.pathname.includes('/login') || u.pathname.includes('/ServiceLogin')));
    } catch (e) { return false; }
}

function applyUserAgentForURL(wv, url) {
    if (!wv || !wv.setAttribute) return;
    if (isGoogleLoginDomain(url)) {
        // Use Chrome 131 for Google to avoid "This browser is not secure" block
        wv.setAttribute('useragent', CHROME_131_UA);
        consoleLog('info', '\uD83D\uDD10 Auto-switched to Chrome UA for Google login');
    } else {
        // Use custom UA if set, otherwise default
        const customUA = localStorage.getItem('ex_ua') || activeUA || navigator.userAgent.replace(/EtherX.*?\s/, '');
        wv.setAttribute('useragent', customUA);
    }
}

// Extensions DB + Manager
const EXT_DB = { get: () => JSON.parse(localStorage.getItem('ex_extensions') || '[]'), save(a) { localStorage.setItem('ex_extensions', JSON.stringify(a)); }, add(ext) { const a = this.get(); if (a.find(e => e.id === ext.id || (ext.path && e.path === ext.path))) { showToast('Already added'); return; } a.push(ext); this.save(a); }, remove(id) { this.save(this.get().filter(e => e.id !== id)); }, toggle(id) { const a = this.get(); const e = a.find(x => x.id === id); if (e) e.enabled = !e.enabled; this.save(a); } };

// Seed default extensions on first run
(function seedDefaultExtensions() {
    const defaults = [
        { id: 'pejdijmoenmkgeppbflobdenhhabjlaj', name: 'iCloud Passwords', icon: '🔑', desc: 'Open Apple/iCloud passwords support externally or via Apple Passwords', enabled: true, source: 'https://chromewebstore.google.com/detail/icloud-passwords/pejdijmoenmkgeppbflobdenhhabjlaj', installMode: 'cws-shortcut', installedAt: Date.now() }
    ];
    const existing = EXT_DB.get();
    let changed = false;
    defaults.forEach(def => { if (!existing.find(e => e.id === def.id)) { existing.push(def); changed = true; } });
    if (changed) EXT_DB.save(existing);
})();

// Seed Reveye bundled extension (unpacked — auto-loaded from app folder at startup)
(async function seedReveyeExtension() {
    if (!window.etherx?.app?.getAppPath) return;
    try {
        const appPath = await window.etherx.app.getAppPath();
        const reveyePath = appPath + '/reveye/src';
        const existing = EXT_DB.get();
        const found = existing.find(e => e.path === reveyePath || e.name === 'RevEye Reverse Image Search' || e.id === 'reveye-builtin');
        if (!found) {
            existing.push({ id: 'reveye-builtin', name: 'RevEye Reverse Image Search', icon: '🔍', desc: 'Reverse image search — Google, Bing, Yandex, TinEye (built-in extension)', enabled: true, installMode: 'unpacked', path: reveyePath, source: 'builtin', installedAt: Date.now() });
            EXT_DB.save(existing);
            renderExtList && renderExtList();
        } else if (!found.enabled) {
            // Builtin extension was toggled off — always keep it enabled
            found.enabled = true;
            EXT_DB.save(existing);
            renderExtList && renderExtList();
        }
    } catch (e) { console.warn('[Ext] Reveye seed failed:', e); }
})();

function renderExtList() {
    const list = document.getElementById('extList');
    if (!list) return;
    const exts = EXT_DB.get();
    if (!exts.length) { list.innerHTML = '<div style="padding:24px;text-align:center;color:var(--text3);font-size:12px"><div style="font-size:32px;margin-bottom:10px">🧩</div>No extensions installed.</div>'; renderExtIconBar(); updateSettingsExtCount && updateSettingsExtCount(); return; }
    list.innerHTML = '';
    exts.forEach(ext => {
        const el = document.createElement('div'); el.className = 'ext-item';
        const modeLabel = ext.installMode === 'unpacked' ? 'Loaded' : (ext.installMode === 'cws-shortcut' ? 'Shortcut' : (ext.enabled ? 'Enabled' : 'Disabled'));
        el.innerHTML = `<div class="ext-item-icon" style="cursor:pointer;position:relative" title="Klikni za promjenu ikone">${ext.icon || '🧩'}<span style="position:absolute;bottom:-2px;right:-2px;font-size:9px;background:var(--accent);border-radius:3px;padding:0 2px;color:#fff;line-height:1.4">✎</span></div><div class="ext-item-body"><div class="ext-item-name">${escHtml(ext.name)}</div><div class="ext-item-desc">${escHtml(ext.desc || '')}</div><div class="ext-item-actions"><button class="ext-toggle${ext.enabled ? ' on' : ''}" data-extid="${ext.id}"></button><span class="ext-badge">${modeLabel}</span><button class="ext-btn-sm" data-del="${ext.id}">Remove</button></div></div>`;
        el.querySelector('.ext-toggle').addEventListener('click', () => { EXT_DB.toggle(ext.id); renderExtList(); renderExtIconBar(); });
        el.querySelector('[data-del]').addEventListener('click', () => {
            window.customConfirm('Remove "' + ext.name + '"?', (c) => { if (c) { EXT_DB.remove(ext.id); renderExtList(); renderExtIconBar(); showToast('🗑 Removed: ' + ext.name); } });
        });
        el.querySelector('.ext-item-icon').addEventListener('click', () => {
            openIconPicker('Promijeni ikonu: ' + ext.name, ext.icon || '🧩',
                ['🧩', '🔑', '📈', '🛡️', '🦊', '🌙', '🔐', '🌐', '⚡', '🎯', '💎', '🔒', '🔓', '🔔', '📌', '🚀', '💰', '🎬', '🤖', '📰', '👥', '⭐', '🕒', '⬇️', '⚙️', '🛠️', '📋', '🔍', '💡', '🎨', '🎵', '📱', '💻', '🌍'],
                (icon) => {
                    const a = EXT_DB.get(); const e = a.find(x => x.id === ext.id);
                    if (e) { e.icon = icon; EXT_DB.save(a); renderExtList(); renderExtIconBar(); showToast('✎ Ikona promijenjena: ' + icon); }
                }
            );
        });
        list.appendChild(el);
    });
    renderExtIconBar();
    updateSettingsExtCount && updateSettingsExtCount();
}

// Render installed extension icons in the title bar
function renderExtIconBar() {
    const bar = document.getElementById('extIconBar'); if (!bar) return;
    const exts = EXT_DB.get();
    bar.innerHTML = '';
    exts.forEach(ext => {
        const pill = document.createElement('div');
        pill.className = 'ext-icon-pill' + (ext.enabled ? '' : ' disabled');
        pill.style.opacity = ext.enabled ? '1' : '0.4';
        pill.title = ext.name + (ext.enabled ? '' : ' (disabled)');
        pill.innerHTML = (ext.icon || '🧩') + `<span class="ext-pill-tooltip">${escHtml(ext.name)}${ext.enabled ? '' : ' ⏸'}</span>`;
        pill.addEventListener('click', () => {
            const url = ext.source || ('https://chromewebstore.google.com/detail/' + ext.id);
            closeAllPanels();
            if (ext.installMode === 'cws-shortcut' && window.etherx?.openExternal) {
                window.etherx.openExternal(url).catch(() => { });
                showToast('🌐 Otvaram ekstenziju izvan EtherX-a: ' + ext.name);
            } else if (ext.installMode === 'unpacked') {
                showToast('🧩 Unpacked extension loaded: ' + ext.name);
            } else {
                navigateTo(url);
                showToast('🧩 Opening: ' + ext.name);
            }
        });
        pill.addEventListener('contextmenu', e => {
            e.preventDefault();
            EXT_DB.toggle(ext.id); renderExtIconBar();
            const updated = EXT_DB.get().find(x => x.id === ext.id);
            showToast((updated?.enabled ? '▶ Enabled: ' : '⏸ Disabled: ') + ext.name);
        });
        bar.appendChild(pill);
    });
}

// ── Icon Picker ──────────────────────────────────────────────────────────
let _iconPickerCallback = null;
function openIconPicker(title, current, presets, callback) {
    _iconPickerCallback = callback;
    document.getElementById('iconPickerTitle').textContent = title || 'Promijeni ikonu';
    const inp = document.getElementById('iconPickerInput');
    inp.value = current || '';
    const presetsEl = document.getElementById('iconPickerPresets');
    presetsEl.innerHTML = '';
    (presets || []).forEach(emoji => {
        const btn = document.createElement('button');
        btn.className = 'icon-preset-btn';
        btn.textContent = emoji;
        btn.addEventListener('click', () => { inp.value = emoji; });
        presetsEl.appendChild(btn);
    });
    document.getElementById('iconPickerOverlay').classList.add('show');
    setTimeout(() => inp.focus(), 50);
}
document.getElementById('iconPickerOk').addEventListener('click', () => {
    const icon = document.getElementById('iconPickerInput').value.trim();
    if (icon && _iconPickerCallback) _iconPickerCallback(icon);
    document.getElementById('iconPickerOverlay').classList.remove('show');
    _iconPickerCallback = null;
});
document.getElementById('iconPickerCancel').addEventListener('click', () => {
    document.getElementById('iconPickerOverlay').classList.remove('show');
    _iconPickerCallback = null;
});
document.getElementById('iconPickerOverlay').addEventListener('click', e => {
    if (e.target === document.getElementById('iconPickerOverlay')) {
        document.getElementById('iconPickerOverlay').classList.remove('show');
        _iconPickerCallback = null;
    }
});
// close on Escape
document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && document.getElementById('iconPickerOverlay').classList.contains('show')) {
        document.getElementById('iconPickerOverlay').classList.remove('show');
        _iconPickerCallback = null;
    }
});

