// ── Featured Extensions Install ──
document.querySelectorAll('.ext-install-btn').forEach(btn => {
    btn.addEventListener('click', async function () {
        const item = this.closest('.ext-feat-item');
        const name = this.dataset.name || 'Extension';
        const desc = this.dataset.desc || '';
        const icon = item?.querySelector('.ext-feat-icon')?.textContent || '🧩';
        const extId = this.dataset.id || name.toLowerCase().replace(/\s+/g, '-');
        const cwsUrl = 'https://chromewebstore.google.com/detail/' + extId;

        // Auto-download CRX if in Electron
        if (window.etherx?.extensions?.downloadFromCWS) {
            showToast('⏳ Downloading & installing ' + name + '...');
            const result = await window.etherx.extensions.downloadFromCWS(extId);
            if (result && result.ok) {
                EXT_DB.add({
                    id: result.id || extId,
                    name: result.name || name,
                    icon: icon,
                    desc: 'Loaded unpacked extension v' + (result.version || '?'),
                    enabled: true,
                    installMode: 'unpacked',
                    path: result.path,
                    source: cwsUrl,
                    installedAt: Date.now()
                });
                showToast('✅ Installed ' + name);
            } else {
                showToast('❌ Install failed: ' + (result?.error || 'Unknown error'));
                return;
            }
        } else {
            // Open in system browser via shell.openExternal
            if (window.etherx?.openExternal) {
                window.etherx.openExternal(cwsUrl);
                showToast('🌐 Otvaranje u sistemskom pregledniku: ' + name);
            } else if (typeof require !== 'undefined') {
                try { require('electron').shell.openExternal(cwsUrl); showToast('🌐 Otvaram CWS: ' + name); }
                catch (e) { navigateTo(cwsUrl); document.getElementById('extPanel')?.classList.remove('open'); }
            } else {
                navigateTo(cwsUrl);
                document.getElementById('extPanel')?.classList.remove('open');
            }
            // Register locally as a shortcut
            EXT_DB.add({ id: extId, name, icon, desc: desc || 'Chrome Web Store shortcut — use Load Unpacked for real runtime.', enabled: true, source: cwsUrl, installMode: 'cws-shortcut', installedAt: Date.now() });
        }

        renderExtList();
        document.querySelectorAll('.ext-tab').forEach(t => t.classList.remove('active'));
        document.querySelectorAll('.ext-pane').forEach(p => p.classList.remove('active'));
        document.querySelector('[data-ext-pane="installed"]')?.classList.add('active');
        document.getElementById('extpane-installed')?.classList.add('active');
    });
});

(async function restoreUnpackedExtensions() {
    const exts = EXT_DB.get();
    let changed = false;
    for (const ext of exts) {
        if (ext.installMode !== 'unpacked' || !ext.path) continue;
        const loaded = await window.etherx?.extensions?.loadUnpacked?.(ext.path);
        if (loaded?.ok) {
            ext.id = loaded.id;
            ext.name = loaded.name || ext.name;
            ext.desc = 'Loaded unpacked extension v' + (loaded.version || '?');
            changed = true;
        }
    }
    if (changed) EXT_DB.save(exts);
    renderExtList();
})();

