// ── Bookmark toolbar: auto-restore on load + settings toggle sync ─────────
(function () {
    // Rebuild the favBar DOM from bookmarks
    function _buildFavBar() {
        let fb = document.getElementById('favBar');
        if (!fb) {
            fb = document.createElement('div');
            fb.id = 'favBar';
            fb.style.cssText = 'height:28px;background:var(--bg2);border-bottom:1px solid var(--border);display:flex;align-items:center;padding:0 8px;gap:4px;flex-shrink:0;font-size:11px;overflow-x:auto';
            const navBar = document.querySelector('.nav-bar');
            if (navBar) navBar.parentNode.insertBefore(fb, navBar.nextSibling);
        }
        const maxBm = parseInt(DB.getSettings().bookmark_bar_max) || 8;
        const bms = DB.getBookmarks().slice(0, maxBm);
        fb.innerHTML = '';
        if (bms.length === 0) {
            fb.innerHTML = '<span style="color:var(--text3);padding:0 8px">Add bookmarks to see them here</span>';
        } else {
            bms.forEach(b => {
                const btn = document.createElement('button');
                btn.style.cssText = 'background:var(--bg3);border:1px solid var(--border2);border-radius:10px;color:var(--text2);padding:2px 10px;cursor:pointer;font-size:11px;white-space:nowrap';
                btn.textContent = '🌐 ' + (b.title || b.url).slice(0, 18);
                btn.addEventListener('click', () => navigateTo(b.url));
                fb.appendChild(btn);
            });
        }
        fb.style.display = 'flex';
        return fb;
    }

    // Expose toggleFavBar globally so menu and settings can call it
    window.toggleFavBar = function (show) {
        let fb = document.getElementById('favBar');
        if (show) {
            if (!fb) fb = _buildFavBar();
            else { _buildFavBar(); fb.style.display = 'flex'; }
        } else {
            if (fb) fb.style.display = 'none';
        }
    };

    // Auto-restore on startup
    try {
        if (DB.getSettings().show_bookmark_bar === true) {
            setTimeout(() => {
                _buildFavBar();
                const chk = document.getElementById('mi-show-favbar-chk');
                if (chk) chk.style.opacity = '1';
                const stChk = document.getElementById('settingShowBookmarkBar');
                if (stChk) stChk.checked = true;
            }, 400);
        }
    } catch (e) { /* ignore */ }
    // Settings toggle → rebuild or hide bar
    const stChk = document.getElementById('settingShowBookmarkBar');
    if (stChk) {
        stChk.addEventListener('change', () => {
            const enabled = stChk.checked;
            const menuChk = document.getElementById('mi-show-favbar-chk');
            if (menuChk) menuChk.style.opacity = enabled ? '1' : '0';
            if (enabled) {
                _buildFavBar();
            } else {
                const fb = document.getElementById('favBar');
                if (fb) fb.style.display = 'none';
            }
        });
    }
    // Max count input → rebuild visible bar
    const maxEl = document.getElementById('settingBookmarkBarMax');
    if (maxEl) {
        maxEl.addEventListener('change', () => {
            const fb = document.getElementById('favBar');
            if (fb && fb.style.display !== 'none') _buildFavBar();
        });
    }
})();

