// ── History viewer in Settings → History ──────────────────────────────────
async function loadIndexHistory(filter) {
    const list = document.getElementById('historyIdxList');
    if (!list) return;
    let entries = [];
    try {
        if (window.etherx?.history?.getAll) {
            entries = await window.etherx.history.getAll() || [];
        }
        // Always merge/fallback with localStorage — SQLite may be empty on first run or macOS
        const localEntries = DB.getHistory() || [];
        if (!entries.length) {
            entries = localEntries;
        } else {
            // Merge: add any localStorage entries not already in IPC result (dedup by URL+ts)
            const ipcUrls = new Set(entries.map(h => (h.url || '') + '|' + (h.visited_at || h.ts || 0)));
            localEntries.forEach(h => {
                const key = (h.url || '') + '|' + (h.visited_at || h.ts || 0);
                if (!ipcUrls.has(key)) entries.push({ ...h, visited_at: h.visited_at || h.ts });
            });
            entries.sort((a, b) => (b.visited_at || b.ts || 0) - (a.visited_at || a.ts || 0));
        }
    } catch (e) { entries = DB.getHistory() || []; }
    if (filter) {
        const f = filter.toLowerCase();
        entries = entries.filter(h =>
            (h.url || '').toLowerCase().includes(f) ||
            (h.title || '').toLowerCase().includes(f)
        );
    }
    if (!entries.length) {
        list.innerHTML = '<div style="text-align:center;padding:24px;color:var(--text3);font-size:12px">Nema rezultata u povijesti.</div>';
        return;
    }
    const groups = {};
    entries.forEach(h => {
        const d = new Date(h.visited_at || h.ts || Date.now()).toLocaleDateString('hr-HR');
        (groups[d] = groups[d] || []).push(h);
    });
    list.innerHTML = '';
    const today = new Date().toLocaleDateString('hr-HR');
    Object.entries(groups).forEach(([day, items]) => {
        const dt = document.createElement('div');
        dt.style.cssText = 'font-size:10px;font-weight:700;text-transform:uppercase;color:var(--text3);padding:6px 12px 4px;background:var(--bg3);position:sticky;top:0;z-index:1;letter-spacing:.5px';
        dt.textContent = day === today ? 'Danas' : day;
        list.appendChild(dt);
        items.forEach(h => {
            const el = document.createElement('div');
            el.style.cssText = 'display:flex;align-items:center;gap:8px;padding:7px 12px;cursor:pointer;border-bottom:1px solid var(--border);transition:.1s';
            el.onmouseenter = () => el.style.background = 'rgba(255,255,255,.04)';
            el.onmouseleave = () => el.style.background = '';
            const time = new Date(h.visited_at || h.ts || Date.now()).toLocaleTimeString('hr-HR', { hour: '2-digit', minute: '2-digit' });
            const esc = s => (s || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
            const fav = `https://www.google.com/s2/favicons?sz=14&domain_url=${encodeURIComponent(h.url)}`;
            el.innerHTML = `<img src="${fav}" width="14" height="14" style="flex-shrink:0;border-radius:2px" onerror="this.style.display='none'">` +
                `<div style="flex:1;min-width:0">` +
                `<div style="font-size:12px;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(h.title || h.url)}</div>` +
                `<div style="font-size:10px;color:var(--text3);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(h.url)}</div>` +
                `</div><span style="font-size:10px;color:var(--text3);flex-shrink:0">${time}</span>`;
            el.addEventListener('click', () => { navigateTo(h.url); closeAllPanels(); });
            list.appendChild(el);
        });
    });
}
function refreshUpdatesPane() {
    const currentTag = (
        document.getElementById('helpVersionNum')?.textContent ||
        document.getElementById('helpVersionNum2')?.textContent ||
        '0.0.0'
    ).replace(/^v/, '');
    const currentVerSpan = document.getElementById('helpVersionNum2');
    if (currentVerSpan) currentVerSpan.textContent = currentTag;
    const badge = document.getElementById('updStatusBadge');
    if (badge && !badge.textContent.trim()) badge.textContent = '✓ Ažuran';
    const lastCheckedEl = document.getElementById('updLastChecked');
    if (lastCheckedEl && !lastCheckedEl.textContent.trim()) lastCheckedEl.textContent = 'Zadnja provjera: nikad';
}
window.refreshSettingsPane = function (stab) {
    const paneId = 'stab-' + stab;
    const pane = document.getElementById(paneId);
    if (!pane) return;

    document.querySelectorAll('.s-tab-pane').forEach(p => p.classList.remove('active'));
    pane.classList.add('active');

    if (stab === 'history') {
        const list = document.getElementById('historyIdxList');
        if (list) list.innerHTML = '<div style="text-align:center;padding:24px;color:var(--text3);font-size:12px">Učitavanje…</div>';
        const query = document.getElementById('histSearchInputIdx')?.value || '';
        loadIndexHistory(query).catch((err) => {
            if (list) list.innerHTML = '<div style="text-align:center;padding:24px;color:#f48771;font-size:12px">Greška pri učitavanju povijesti: ' + escHtml(err?.message || 'nepoznato') + '</div>';
        });
        return;
    }
    if (stab === 'updates') {
        try {
            refreshUpdatesPane();
            if (typeof window.checkForUpdates === 'function') {
                window.checkForUpdates(true).catch(() => { });
            }
        } catch (err) {
            const resultBox = document.getElementById('updResultBox');
            const label = document.getElementById('updNewVerLabel');
            const notes = document.getElementById('updReleaseNotes');
            if (resultBox) resultBox.style.display = 'block';
            if (label) {
                label.style.color = '#e74c3c';
                label.textContent = '❌ Greška pri učitavanju updates taba';
            }
            if (notes) notes.textContent = String(err?.message || 'Nepoznata greška');
        }
        return;
    }
    if (stab === 'ai' && window.renderAiHistory) {
        window.renderAiHistory();
    }
};
