// ── Profile Creation ──
document.getElementById('sNewProfile')?.addEventListener('click', () => {
    window.customPrompt('Enter profile name:', '', (name) => {
        if (!name || !name.trim()) return;
        const profiles = JSON.parse(localStorage.getItem('ex_profiles') || '[]');
        if (profiles.find(p => p.name === name.trim())) { showToast('Profile already exists'); return; }
        profiles.push({ name: name.trim(), ts: Date.now(), active: false });
        localStorage.setItem('ex_profiles', JSON.stringify(profiles));
        window.refreshProfileDropdown?.();
        window.refreshSettingsProfiles?.();
        showToast('Profile created: ' + name.trim());
    });
});

// Load saved profiles on init
(function initProfilesUI() {
    const nameInput = document.getElementById('sProfileNameInput');
    if (nameInput) {
        const u = DB.getUser();
        nameInput.value = u.name || '';
        nameInput.addEventListener('change', () => { DB.saveUser({ name: nameInput.value }); showToast('✅ Name updated'); });
    }

    window.refreshSettingsProfiles = function () {
        const pane = document.getElementById('stab-profiles');
        const grp = document.getElementById('sPersonaGroup');
        if (!pane || !grp) return;
        grp.innerHTML = '<div class="s-group-title">Browser Personas</div>';

        const defName = localStorage.getItem('ex_default_persona_name') || 'Default';
        const active = localStorage.getItem('ex_active_profile') || defName;
        const profiles = [{ name: defName, isDefault: true }].concat(JSON.parse(localStorage.getItem('ex_profiles') || '[]'));

        profiles.forEach(p => {
            const row = document.createElement('div'); row.className = 's-row';
            const isActive = p.name === active;
            row.innerHTML = `<div class="s-row-left"><div class="s-row-label">${p.name}</div><div class="s-row-desc">${p.isDefault ? 'System profile' : 'Custom persona'}</div></div>
            <div style="display:flex;align-items:center;gap:6px">
              ${isActive ? '<span style="color:var(--green);font-size:11px">✓ Active</span>' : `<button class="s-btn-sm" data-switch="${p.name}">Switch</button>`}
              <button class="s-btn-sm" data-rename="${p.name}">Rename</button>
              ${!p.isDefault ? `<button class="s-btn-sm" style="color:var(--red)" data-del="${p.name}">Remove</button>` : ''}
            </div>`;

            row.querySelector('[data-switch]')?.addEventListener('click', () => {
                localStorage.setItem('ex_active_profile', p.name);
                window.refreshProfileDropdown?.();
                window.refreshSettingsProfiles();
                showToast('👤 Switched to: ' + p.name);
            });

            row.querySelector('[data-rename]')?.addEventListener('click', () => {
                window.customPrompt(`Rename persona "${p.name}" to:`, p.name, (newName) => {
                    if (!newName || !newName.trim() || newName === p.name) return;
                    if (p.isDefault) {
                        localStorage.setItem('ex_default_persona_name', newName.trim());
                    } else {
                        const pp = JSON.parse(localStorage.getItem('ex_profiles') || '[]');
                        const found = pp.find(x => x.name === p.name);
                        if (found) { found.name = newName.trim(); localStorage.setItem('ex_profiles', JSON.stringify(pp)); }
                    }
                    if (active === p.name) localStorage.setItem('ex_active_profile', newName.trim());
                    window.refreshProfileDropdown?.();
                    window.refreshSettingsProfiles();
                    showToast('Profile renamed');
                });
            });

            row.querySelector('[data-del]')?.addEventListener('click', () => {
                window.customConfirm(`Remove persona "${p.name}"?`, (c) => {
                    if (!c) return;
                    const pp = JSON.parse(localStorage.getItem('ex_profiles') || '[]');
                    localStorage.setItem('ex_profiles', JSON.stringify(pp.filter(x => x.name !== p.name)));
                    if (active === p.name) localStorage.setItem('ex_active_profile', defName);
                    window.refreshProfileDropdown?.();
                    window.refreshSettingsProfiles();
                    showToast('Profile removed');
                });
            });
            grp.appendChild(row);
        });
    };
    window.refreshSettingsProfiles();
})();
